import { useEffect, useState } from "react";
// import axios from "axios";

function Leads() {
    const [leads, setLeads] = useState([]);
    // const [loading, setLoading] = useState(true);
    // const [error, setError] = useState("");
    const [showDecrypted, setShowDecrypted] = useState(false);

    // const fetchLeads = async (decrypted = false) => {
    //     try {
    //         const res = await axios.get("http://localhost:8000/leads", {
    //             params: { decrypted: decrypted ? 1 : 0 },
    //         });
    //         setLeads(res.data || []);
    //         console.log("Fetched leads:", res.data);
    //     } catch (err) {
    //         console.error("Error fetching leads:", err);
    //         setError("Failed to load leads. Please try again later.");
    //     } finally {
    //         setLoading(false);
    //     }
    // };

    useEffect(() => {
        fetch("http://localhost:8000/leads") // your FastAPI URL
            .then((res) => res.json())
            .then((data) => {
                console.log("API Response:", data);
                setLeads(data.leads); // store leads array
            })
            .catch((err) => console.error("Error fetching leads:", err));
    }, []);

    // useEffect(() => {
    //     fetchLeads(showDecrypted);
    // }, [showDecrypted]);

    return (
        <div className="container mt-4">
            <div className="card shadow-lg border-0 rounded-3">
                <div className="card-header d-flex justify-content-between align-items-center bg-dark text-white">
                    <h4 className="mb-0">📋 Leads</h4>

                    <button
                        className="btn btn-light btn-sm shadow-sm"
                        onClick={() => setShowDecrypted((prev) => !prev)}
                    >
                        {showDecrypted ? "🔒 Show Encrypted" : "🔑 Show Decrypted"}
                    </button>
                </div>

                <div className="card-body">
                    {leads.length > 0 ? (
                        <div className="table-responsive">
                            <table className="table table-hover align-middle table-bordered">
                                <thead>
                                    <tr>
                                        <th>First Name</th>
                                        <th>Last Name</th>
                                        <th>Email</th>
                                        <th>Phone</th>
                                        <th>Company</th>
                                        <th>Domain</th>
                                        <th>Campaign</th>
                                        <th>Date</th>
                                        <th>Followed By</th>
                                        <th>Uploaded By</th>
                                        <th>Uploaded Date</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {leads.map((lead) => (
                                        <tr key={lead.id}>
                                            <td>{lead.first_name || "-"}</td>
                                            <td>{lead.last_name || "-"}</td>
                                            <td>{lead.email || "-"}</td>
                                            <td>{lead.phone || "-"}</td>
                                            <td>{lead.company || "-"}</td>
                                            <td>{lead.domain || "-"}</td>
                                            <td>{lead.campaign || "-"}</td>
                                            <td>{lead.date || "-"}</td>
                                            <td>{lead.followed_by || "-"}</td>
                                            <td>{lead.uploaded_by || "-"}</td>
                                            <td>{lead.uploaded_dt || "-"}</td>
                                        </tr>

                                    ))}
                                </tbody>
                            </table>
                        </div>
                    ) : (
                        <p className="text-muted text-center">No leads found.</p>
                    )}
                </div>
            </div>
        </div>
    );
}

export default Leads;
